-- Catalogue officiel des 220 badges (Phase 1 : définitions).
-- Modèle uniforme : chaque badge est un palier (metric, threshold).
-- Le moteur d'attribution et les métriques sont (re)construits aux phases suivantes.

delete from public.profile_badges where source = 'auto';
delete from public.badges;

create or replace function public.recalculate_profile_badges(p_profile_id uuid)
returns void language plpgsql security definer set search_path to 'public'
as $fn$ begin return; end; $fn$;

create or replace function public.recalculate_all_badges()
returns void language plpgsql security definer set search_path to 'public'
as $fn$ begin return; end; $fn$;

create or replace function public.award_season_titles(p_season_id uuid)
returns void language plpgsql security definer set search_path to 'public'
as $fn$ begin return; end; $fn$;
